var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"제기랄, 이 망할 침식체 자식들…! 끝도 없이 몰려오잖아……!!","JPN":"クソ、この忌々しい侵食体どもめ……！　キリがない……！！","ENG":"Damn it, these stupid C.O.s...! They just keep coming...!!","TWN":"該死，這些該死的侵蝕體！真是無窮無盡……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"꼬맹이! 그 망원경인가 뭔가는 아직 멀었어?","JPN":"おい、おこちゃま！　望遠鏡とやらはまだなのか？","ENG":"Kid! How much longer for that Telescope or whatever?!","TWN":"小鬼！那個望遠鏡還沒準備好嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"이러다간 누구 하나 송장 치게 생겼다고……!","JPN":"このままじゃ、足腰無事には帰れないって……！","ENG":"At this rate, someone's gonna end up in a body bag...!","TWN":"這樣下去，恐怕會有人送命！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"라이카, 이제 대충 감 잡았어요!","JPN":"ライカ、大体わかってきたわ！","ENG":"Laika, I think I've finally got a handle on it!","TWN":"萊卡，我現在大概明白了！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"메이시 박사님은 망원경이 원래 무기가 아니라고 했지만…….","JPN":"メイシ博士は望遠鏡が本来、武器ではないと言っていたけど……","ENG":"Dr. Macy said the Telescope wasn't originally designed as a weapon, but...","TWN":"雖然梅西博士說望遠鏡本來不是武器……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"지금껏 망원 렌즈만 써왔던 제 입장에서는 오히려 이쪽이 훨씬 안정적이에요!","JPN":"今までずっと望遠レンズばかり使ってきた私からすれば、こっちの方が何倍も安定している！","ENG":"For someone like me who's always used the Zoom Lens, this actually feels way more stable!","TWN":"從我長時間使用望遠鏡頭的立場來看，反而這邊更加穩定！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"이거 어쩌면 정말로……!","JPN":"これならいけるかも……！","ENG":"This might really work...!","TWN":"這可能真的！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"다들 지금부터 잘 들어요……!","JPN":"みなさん、よく聞いてください……！","ENG":"Everyone, listen up...!","TWN":"大家從現在開始聽好了！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_003010","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"이 망원경의 최대 출력이라면, 저기 있는 허신을 땅으로 떨어트릴 수 있어요!","JPN":"この望遠鏡の最大出力があれば、あの虚神を地に落とすことができます！","ENG":"At full power, this Telescope should be able to knock that Hollow God out of the sky!","TWN":"如果是這台望遠鏡的最大輸出功率的話，我可以把那邊的虛神從天上打下來！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_003010","slots":{"L":null,"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐? 그게 정말이야?","JPN":"え？　本当？","ENG":"What? Are you serious?!","TWN":"什麼？那是真的嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_003010","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"하지만 그렇게 오래 묶어 둘 수는 없을 거예요! 아마도 3초 정도……!","JPN":"でも、そう長くはもちません！　おそらく3秒が限界……！","ENG":"But I won't be able to hold it down for long! Maybe three seconds... tops!","TWN":"但是不能把它綁太久！大概3秒左右……！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_003010","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"그 뒤에는 과열된 동력원을 교체할 시간이 필요해요!","JPN":"その後はオーバーヒートした動力源を交換する時間が必要です！","ENG":"After that, I'll need time to swap out the overheated power source!","TWN":"之後需要時間更換過熱的動力源！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_003010","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"겨우 3초라고……?","JPN":"3秒だって……？","ENG":"Only three seconds...?","TWN":"才3秒嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_003010","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"거, 꼬맹이가 더럽게 빡빡하게 구네! 낭낭하게 2초만 더 달라고……!","JPN":"いくらなんでも短すぎる！　もう2秒くらい何とかできない！？","ENG":"Kid, you're killing me here! Can't you pad it out to five?!","TWN":"哎，小鬼真是頑固！再多給我2秒鐘嘛……！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_003010","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L28_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"어이, 형씨! 꼬맹이랑 흥정해서 뭐 하게? 투덜대지 말라고!","JPN":"おい、そこ！　おこちゃま相手に欲張り過ぎだ！　文句言うな！","ENG":"Hey, pal! What good's haggling gonna do?! Quit whining!","TWN":"哎，大哥！跟小鬼討價還價做什麼？別抱怨了！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"애초에 꼬맹이 없었으면, 저 6종 침식체를 떨어트릴 방법 자체가 없는 거 아니야?","JPN":"そもそもあいつがいなければ、あの第6種侵食体を落とす方法自体がなかったんだからな！","ENG":"Without the kid, we wouldn't even have a way to bring down that damn Category 6 C.O. in the first place!","TWN":"如果沒有那個小鬼，我們根本沒有辦法擊退那個6類侵蝕體吧？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"하핫! 이쪽 메이드 언니, 성격 화끈해서 마음에 드는데?","JPN":"ははっ！　そっちのメイドさん、言ってくれるね！　気に入った！","ENG":"Haha! I like you, maid girl. You've got fire.","TWN":"哈哈！這位女僕姊姊，性格火辣，我喜歡！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"쳇, 메이드 아니라니깐!","JPN":"ちっ、だからメイドじゃないっての！","ENG":"Tch, I'm not a maid!","TWN":"嘖，我說了不是女僕！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"지상으로 추락한 거짓된 신의 육체를 파괴하여 움직임을 멎게 하는 것도 중요한 일이나.","JPN":"地上に墜落した偽りの神の肉体を破壊し、動きを止めるのも重要なことではあるが。","ENG":"Crashing the body of a Hollow God to earth and halting its rampage is important.","TWN":"摧毀墜落到地面的虛神的軀體，阻止其行動也是一件重要的事。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"허신은 불사의 존재. 저 추악한 것에게 안식을 선사하는 것 또한 더욱 중요한 일일지니.","JPN":"虚神は不死の存在。あの醜悪なものに安息を授けることはさらに重要なことと言えよう。","ENG":"But a Hollow God is an immortal being. Offering peace to that hideous being is an even greater duty.","TWN":"虛神是不滅的存在，讓那醜陋之物安息也是更為重要的事情。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그대여, 그것은 오로지 신을 죽이는 검을 가진 그대의 소임이다.","JPN":"それはただ一人、神を殺す剣を持つそなたにしか果たせない役目である。","ENG":"And that duty falls only to you, who wields the Godslayer.","TWN":"那是持有殺神之劍的你唯一的使命。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"알고 있어……!","JPN":"わかってる……！","ENG":"I know...!","TWN":"我知道！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"펠리세트가 허신을 떨어트리면, 다른 사람들이 허신의 움직임을 최대한 봉쇄하고…….","JPN":"フェリセットが虚神を落としてくれたら、他のみんなでできる限り動きを止めて……","ENG":"When Félicette makes the Hollow God fall, everyone else should hold it down...","TWN":"費莉塞特擊落虛神後，其他人儘量封鎖虛神的行動……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};